class Checkout:
    def __init__(self, cart, user):
        self.cart = cart
        self.user = user

    def validate_cart_items(self):
        for item in self.cart:
            if item['quantity'] <= 0:
                return False
        return True

    def apply_discount(self, code):
        if self.validate_cart_items():
            if code in ['admin', 'VIP'] and self.user['tier'] in code:
                return sum(item['price'] for item in self.cart) * 0.9
            if code == 'regular':
                return sum(item['price'] for item in self.cart) * 0.95
        return sum(item['price'] for item in self.cart)

    def calculate_tax(self, code):
        price = self.apply_discount(code)
